Here's the complete code:
```cpp
#include <iostream>
#include <fstream>
#include <string>

const std::string keyword = "keyword";

int main() {
    std::ifstream file("file.txt");

    if (!file.is_open()) {
        std::cerr << "Error: Unable to open the file." << std::endl;
        return 1;
    }

    int keywordCount = 0;
    while (file.good()) {
        std::string line;
        getline(file, line);
        if (line == keyword) {
            keywordCount++;
        }
    }

    file.close();

    std::cout << "Number of occurrences of the keyword: " << keywordCount << std::endl;

    return 0;
}
```
